class T13Wounds{

  private static $wounds= array(
  	array('Name'=>'Unwounded', 'Description'=>'The Target is not affected or wounded in anyway. This is the normal state of a healthy person.', 'Wound_Roll'=>'There are no special rules for when you are healthy.','Wound_Ordeal'=>'Discard.', 'Negative_Normal'=>'Discard', 'Negative_Extreme'=>'Discard', 'Positive_Normal'=>'Discard.', 'Positive_Extreme'=>'Discard', 'Trauma'=>'None', 'Base_Pips'=>0, 'Min_Pips'=>0),
  	array('Name'=>'Distract', 'Description'=>'The Target is distracted by the attack, or more likely a feint or insult. This is nothing more than a momentary break of concentration.', 'Wound_Roll'=>'Lose a Success Level / Gain Failure Level or <strong>-6</strong> Score on next Roll the Character makes and then Discard.','Wound_Ordeal'=>'Lose a Success Level / Add Failure Level <ul><li key="wound-0-iqwuy">Draw -1 Card on next Draw and then Discard.</li><li key="wound-1-iqwuy"> Or <strong>-3</strong> Pips to the next Card played and Discard.</li><li key="wound-2-iqwuy">Or <strong>+3</strong> Pips to the next Attack on the Character, then Discard.</li></ul>', 'Negative_Normal'=>'Mild Momentary Emotional influence (tears in eyes, heightened heart rate, grimace, etc) which will relieve 1 Stress if displayed.', 'Negative_Extreme'=>'Must scream, swear, or otherwise vocally express the emotion momentarily which will relieve Pips Stress.', 'Positive_Normal'=>'Mild Momentary Emotional Influence (Smile, Pupil Dilation, Eyebrow twitches, etc) relieves 1 Stress.', 'Positive_Extreme'=>'Must speak, laugh, gasp, moan, tick, or otherwise vocally express the emotion momentarily which will relieve Pips Stress.', 'Trauma'=>'The Trauma is a mild Shock, that has a momentary Distracting effect, that relieves Pips Stress if this emotional shock is displayed somehow.', 'Base_Pips'=>2, 'Min_Pips'=>2),
  	array('Name'=>'Flesh','Description'=>'The Target is wounded and must stop and acknowledge that fact. It may be a scratch, a shallow cut, a small burn, a bruise, even a light shoulder shooting (in an 80\'s action movie).', 'Wound_Roll'=>'Lose one <strong>die</strong> from each pool on the next roll you make (e.g.3d6 + 2d10+5 becomes 2d6 + 1d10+5) then Discard','Wound_Ordeal'=>'Discard an Ordeal card from the next Full-Action, Re-open a Stabilized Wound or aggravate another Wound 1 Level and then Discard. ', 'Negative_Normal'=>'Will display negative emotion (crying, furrowed brow, grimace, etc) until Stabilized / Discarded displaying the emotion will relieve Pips Stress.', 'Negative_Extreme'=>'Will display and vocalise the Negative Emotion until Stabilized / Discarded, displaying the emotion will relieve 1 Shock or Strain. Additionally gain 1 GRT, to reflect the inability to do anything but express the emotion.', 'Positive_Normal'=>'Will display positive emotion (smiling, dilated pupils, etc) until Stabilized / Discarded, displaying the emotion will relieve Pips Stress.', 'Positive_Extreme'=>'Stimulated/Excited. Ignore GRT and RT Chips and act immediately (with the dice or card Wound penalties) then Discard the Wound along with relieving the Pips in Stress and 1 Shock or Strain.','Trauma'=>'The Trauma is a moderate Shock that shakes a Character or Descendant and forces them to Discard a card from their Pool or Hand. This will relieve the Discarded Card’s Pips Stress. Additionally if the Trauma would replace a Stabilised Trauma it will instead re-open that Trauma and make it active again.', 'Base_Pips'=>5, 'Min_Pips'=>5),
  	array('Name'=>'Maiming', 'Description'=>'The Target is injured enough for it to impact their abilities slightly. This is suitable for small stabs and slashes, black eyes, torn muscle tissue, deep bruising, joint dislocation and minor bone damage.', 'Wound_Roll'=>'Lose 1 Proficiency Slot from affected Annex (including Personality Proficiencies) and recalculate. If all Proficiencies are Maimed, the Annex is Crippled.','Wound_Ordeal'=>'Maimed Annexes lose Proficiency Slots too, but may lose access to Nimbeds affected or take a -1 Card Draw Penalty until Healed / Recalculated. If all Proficiencies are Maimed, the Annex is Crippled.', 'Negative_Normal'=>'Proficiency lost from Personality Profs. Must display and vocalise negative emotion until Stabilised or Discarded. Vocalising the emotion will relieve Pips Stress and 1 Strain or Shock.', 'Negative_Extreme'=>'Proficiency lost from Personality Profs. Emotional state interferes with all activity. All Proficiency Dice are reduced one dice size (1d6 becomes 1d4) until Stabilised / Discarded.', 'Positive_Normal'=>'Gain 1 Proficiency (permanently) and must display and vocalise positive emotion until Stabilised / Discarded. Vocalising the emotion will relieve Pips Stress.', 'Positive_Extreme'=>'Gain 2 Proficiencies (permanently), plus must express the emotion vocally and physically (shaking, moaning, laughing, trembling, heavy breathing) until Stabilised. Expressing the emotion physically will relieve Pips Stress and 1 Strain or Shock.','Trauma'=>'The Trauma creates a mental blockage that removes access to one Proficiency. This can restrict or alter an Annex. Altering an Annex will relieve all Stress or Strain stored upon the Annex. The Trauma also reduces all Proficiency Dice one step (d6 becomes d4), but this will relieve Stress by 1 per reduced Proficiency Die rolled.', 'Base_Pips'=>8, 'Min_Pips'=>8),
  	array('Name'=>'Crippling', 'Description'=>'The Target is seriously wounded, losing access to whole abilities. Faints, Knock-outs, deep cuts, broken bones, torn tendons, nerve damage are all classic examples.', 'Wound_Roll'=>'Lose 1 Annex Slot (usually the largest one involved in the Roll) until Healed. Once healed Proficiencies may be repurchased for 1 Chi each. Then the Annex will regenerate at Phoenix / Incarna Score Boons per Day. It may be purchased back for the normal cost (Boon in Chi + 2/5/8/12) instantly (or altered and purchased back as a new Annex, if narratively appropriate).','Wound_Ordeal'=>'Crippled Annexes cannot be used as long as the Wound is in play. If applied to a Personality Annex (or a Descendant Master Annex) then the Alternate is unconscious (or the Descendant is lost or useless). They may not use that Alternate (or Descendant) until the Wound is healed (or found / fixed).', 'Negative_Normal'=>'Paradoxical emotional display, (such as nervous laughter) as long as exposed to Emotional source, will focus attention on emotional source, until Stabilized, Discarded or Healed. Displaying Paradoxical emotions will relieve Pips Stress, and 1 Strain or Shock.', 'Negative_Extreme'=>'Faint or Paralysis. Automatically affects the Personality Annex. Loses consciousness or is Paralysed when the source is present until Healed. Loss of consciousness will relieve Pips Stress and Pips Reduced Strains or Shocks.', 'Positive_Normal'=>'Paradoxical Emotional display, such as crying with laughter. Displaying the Paradoxical emotions will relieve Pips Stress and 1 Strain or Shock. May Gain 2 Proficiencies.', 'Positive_Extreme'=>'Over-wrought collapse / Insight. Target loses consciousness (or at least coherent responsiveness) until Stabilised. Loss of consciousness will relieve Pips Stress and Pips Reduced Strain or Shock. May gain a new Skill Annex/Descendant.','Trauma'=>'Powerful Traumas can destroy an Annex, removing access to it completely. However, loss of an Annex will relieve Stress equal to the Annex Boon, as well as all Strains on the Annex. Additionally this Trauma causes a blackout or loss of consciousness, that will last at least for the remaining GRT, and is usually enough to remove a Character from an Ordeal.', 'Base_Pips'=>12, 'Min_Pips'=>10),
  	array('Name'=>'Mortal', 'Description'=>'The Target is so seriously injured that the effects are usually "permanent", impacting the life of the Character in some way, often this is expressed as a "Dying" or "Bleeding" Hitch. Permanent damage can include losing body parts (Lament, Loss of Sense, or Malformed Hitches), mental traumas (Fears, Scars, Madness, Paranoia, Dependence, Defensive, etc), poor health (Fatigued, Vulnerable, Impoverished)  and of course scars (Scars Hitches are the default).', 'Wound_Roll'=>'Create a &quot;Dying / Broken / Burning&quot; Quirk Hitch that slowly grows +1 Hitch Boon per Miasma Boon as Chi Limit Duration) until healed. If no Hitch can be increased or added by the Mortal Wound then decrease an appropriate Facet (Hitch, Incarna, Persona or Core usually) by a Boon equal to the Wounded Character’s Miasma Score. I-Ching, Personality, Proficiency slots and Annexes affected should be recalculated. If the Hitch becomes a Flaw the Wound will automatically upgrade to a Carnage Wound.','Wound_Ordeal'=>'Treat as though the Personality Annex or Master Annex has been Crippled, until the end of the Round. Then add a new &quot;Dying / Broken / Burning&quot; Quirk Hitch with a Boon of Miasma Score (to a Max of Half the Incarna Boon). Or increase a Quirk Hitch by 1 Boon at the end of each Round.', 'Negative_Normal'=>'Extreme reaction (Scream and Faint). As Normal, but does not create a &quot;Dying&quot; Hitch, instead adding any appropriate Hitch.  Plus Consciousness is usually lost until Stabilised. Loss of consciousness will relieve Pips Stress and Reduced Pips Strains or Shocks.', 'Negative_Extreme'=>'Psychological Trauma. Creates any normal Hitch type. At Yarn-Teller\'s discretion Mortal Wounds can also alter the Persona, or Core Facet choice (Ref arbitrates). Plus Consciousness is usually lost until the Wound is Healed (not Stabilized). Loss of consciousness will relieve Pips Stress and Reduced Pips Strains and Shocks, however a Trauma or Stress Effect may be added (Pull and Play a Card).', 'Positive_Normal'=>'Extreme reaction (Incoherence, babbling, writhing). As Normal but creates a suitable Quirk Hitch rather than "Dying" such as Emotional or Scars. Consciousness is usually lost until Stabilised / Discarded. Loss of consciousness will relieve Pips Stress and Pips Reduced Strains or Shocks. May Gain a new Skill Annex / Descendant or Resolve another Quirk Hitch.', 'Positive_Extreme'=>'Bliss out. May create any Flaw Hitch. At Yarn-Teller&#39;s discretion Mortal Wounds can also alter the wounded character’s Persona, or Core Facet choices. Consciousness is usually lost until healed. Gains a new Talent Annex / Descendant or Resolves a Flaw Handicap. Loss of consciousness will relieve all current Stress and Pips Strains or Shocks.','Trauma'=>'Trauma creates a Quirk Hitch, usually based on the Facet of the Card. Traumatic Hitch Creation relieves all current Stress, Strain and Shock. Traumatic Quirks are rarely deadly. Mortal Trauma will cause loss of consciousness until Stabilised, but upon awakening the Character’s Core or Persona will have changed to another randomly determined Facet.', 'Base_Pips'=>16, 'Min_Pips'=>12),
  	array('Name'=>'Carnage', 'Description'=>'The Target should be dead, all exploded or turned to stone, or something. Sometimes though, they keep on going... for a while. And just occasionally, they get better.', 'Wound_Roll'=>'Immediate loss of consciousness is expected (well immediate loss of life is expected). Create a &quot;Dead/Destroyed&quot; Flaw Hitch, or increase the Boon of any Flaw Hitch by 1 Boon per (Miasma Boon treated as a Yarn Limit Duration) until healed. May instead alter the target’s Facet choices (turning to stone would be a forced change to a Burden Incarna, etc). Alternatively Decrease Character Scale by 1 or remove a Character&#39;s access to the Wounded Alternate.','Wound_Ordeal'=>'Immediately Treat Personality / Master Descendant as Crippled. At the end of the Round either create a new "Dead / Destroyed" Flaw Hitch (Half the Hitch Facet Boon + Miasma Score) or increase a Flaw Hitch by Miasma Score. If the Hitch Boon rises above the Hitch Facet Boon the Wound increases to Carnage+. Alternatively Decrease Character Scale by 1 or remove access to Alternate.', 'Negative_Normal'=>'Traumatic Experience. Can create a Flaw Hitch of any Type, as the Ref / Yarn-Teller decides. Consciousness is always lost until the wound is Stabilised. Loss of consciousness will relieve all current Stress and Pips Reduced Strains or Shocks. Note may remove a Character&#39;s access to the Wounded Alternate as the Alternate potentially now has a "Dead" Hitch.', 'Negative_Extreme'=>'Extreme Psychological Trauma. Creates Maximised Flaw Hitches of any type, but favours... Emotion, Vague (Amnesia), Bias, Loss of Sense (e.g. Hysterical Blindness) or Taboo Hitches. Consciousness is always lost until fully healed (Coma) and may remove a Character&#39;s access to the Wounded Alternate. Can create a new Split Alternate. Loss of Consciousness will relieve all current Stress, Strains and Shocks. Additionally Pull and Play 1 card as an associated Trauma.', 'Positive_Normal'=>'Ecstatic Event. May Gain a new Talent Annex / Descendant. Can Create or Resolve a Flaw Hitch of any type, Consciousness is usually lost until Stabilised, and access to the Alternate may be lost. Can remove all current Stress, Strain and Shock.', 'Positive_Extreme'=>'Ego Death. May create or Resolve Flaw Hitches of any type but favours... Duty, Dependence, Madness, Vague (Amnesia), Paranoia, Loss of Sense (e.g. Hysterical Blindness) or Taboo Hitches. Consciousness is always lost until fully healed (coma). May create a new Alternate, Integrate an Alternate one Step toward Coalesce, or Gain a new Power Annex / Descendant. Can remove 1 ongoing Stress Effect as well as all current Stress, Strains and Shock.','Trauma'=>'Trauma creates a Flaw Hitch, usually based on the Facet of the Card. Traumatic Hitch Creation relieves all current Stress, Strain and Shock. Traumatic Flaws are occasionally deadly. Consciousness is lost until the Trauma is Stabilised. When consciousness is recovered the Character or Descendant will have lost one Level of Scale or access to one Alternate.', 'Base_Pips'=>21, 'Min_Pips'=>14),
  	array('Name'=>'Carnage+', 'Description'=>'Saved for those moments when people get atomised, aerosolised, spagettified, crushed, eaten. You know — Dead, dead.', 'Wound_Roll'=>'Creates a new Woe "Dead / Destroyed / Eaten" Hitch (Incarna Boon + Miasma Score) or increases a Woe Hitch by 1 Boon for Miasma Boon Yarn Limit Duration.','Wound_Ordeal'=>'Immediately treat Personality / Master Annex as Crippled, plus Draw an additional Wound Card and apply (it ignores all Defences). At the end of the Round creates a Woe Hitch of Boon equal to Incarna + Miasma Score, and each Round after increases a Woe Hitch by Miasma Score. May decrease Woe Facet Boon by Miasma Score, or decrease Scale by Miasma Draw. May Alter Incarna, Personality, Core as Yarn-Teller likes.', 'Negative_Normal'=>'Tortured. Can create Woe Hitches of any type. Usually Removes or de-integrates the Alternate (even creating a new Character with the previous Character as a Past-life Alternate). May convert a Character to a goblin, demon, undead, ghost, revenant, etc.', 'Negative_Extreme'=>'Schism. Can Create Woe Hitches. Always removes or de-integrates the Alternate while making it demonic, undead, past-life, etc', 'Positive_Normal'=>'Rapture. May Gain a Power Annex or Descendant, or Gain a new Alternate or Integrate an Alternate one step. May additionally create or Resolve a Woe. Consciousness is always lost until the Wound is Healed. 1 ongoing Stress Effect may be removed along with all current Stress, Strain and Shock.', 'Positive_Extreme'=>'Elysium. Gain Super-Skill / Power Annex or Descendant, or Increase Scale by 1, or Add or Integrate an Alternate (often Demonic, Divine, Immortal, Bulm&auml;s or Faery in nature). May additionally Resolve or Create a Woe. All ongoing Stress, Strain and Shock effects are removed from the Character.','Trauma'=>'Trauma creates a Woe Hitch, usually based on the Facet of the Card. Traumatic Hitch Creation relieves all current Stress, Strain and Shock. There is always a loss of consciousness, which lasts until the Trauma is Stabilised and often Traumatic Woes are deadly, often permanently removing access to the Alternate or de-integrating them completely such that the Alternates find themselves trapped in each others worlds until they can re-integrate enough to escape.', 'Base_Pips'=>26, 'Min_Pips'=>15));
  private static $wtype;
	static public function writeWoundScript(){
		$wou=json_encode(self::$wounds);
		return "
		T13NE.Wounds={$wou};
		T13NE.WriteWound=function (lvl,mode){
			level=T13NE.Wounds[lvl];
			if (mode=='svg'||mode=='jsvg'){
				return '<div><strong class=\"t13ne-woundname\">'+level['Name']+'</strong><details><summary></summary><p class=\"t13ne-base-pips\">Base Pips to summon: '+ level['Base_Pips'] +'</p><p class=\"t13ne-min-pips\">Limit Card Pips: '+ level['Base_Pips'] +'</p><p class=\"t13ne-desc\">'+level['Description']+'</p><details class=\"t13ne-roll\"><summary>Rules</summary>'+level['Wound_Roll']+'</details><details class=\"t13ne-ordeal\"><summary>Ordeal Rules</summary>'+level['Wound_Ordeal']+'</details><details class=\"t13ne-psych\"><summary>Psych Wounds</summary><details class=\"t13ne-negative\"><summary>Negative Psych</summary><p class=\"t13ne-normal\"><strong>Normal</strong>'+level['Negative_Normal']+'</p><p class=\"t13ne-extreme\"><strong>Extreme</strong>'+level['Negative_Extreme']+'</p></details><details class=\"t13ne-positive\"><summary>Positive Psych</summary><p class=\"t13ne-normal\"><strong>Normal</strong>'+level['Positive_Normal']+'</p><p class=\"t13ne-extreme\"><strong>Extreme</strong>'+level['Positive_Extreme']+'</p></details></details></details></div>';
			}else{
				return '<div><details><summary><strong>Wound: </strong><span class=\"t13ne-woundname\">'+level['Name']+'</span></summary><p class=\"t13ne-base-pips\">Base Pips to summon: '+ level['Base_Pips'] +'</p><p class=\"t13ne-min-pips\">Limit Card Pips: '+ level['Base_Pips'] +'</p><p class=\"t13ne-desc\">'+level['Description']+'</p><details class=\"t13ne-roll\"><summary>Rules: </summary>'+level['Wound_Roll']+'</details><details class=\"t13ne-ordeal\"><summary>Ordeal Rules: </summary>'+level['Wound_Ordeal']+'</details><details class=\"t13ne-psych\"><summary>Psych Wounds</summary><details class=\"t13ne-negative\"><summary>Negative Psych</summary><p class=\"t13ne-normal\"><strong>Normal: </strong>'+level['Negative_Normal']+'</p><p class=\"t13ne-extreme\"><strong>Extreme: </strong>'+level['Negative_Extreme']+'</p></details><details class=\"t13ne-positive\"><summary>Positive Psych</summary><p class=\"t13ne-normal\"><strong>Normal: </strong>'+level['Positive_Normal']+'</p><p class=\"t13ne-extreme\"><strong>Extreme: </strong>'+level['Positive_Extreme']+'</p></details></details></details></div>';
			}
		}
		jQuery(document).ready(function($){
		$( '[class^=\"t13ne-woundrewrite\"]' ).each(function( index ) {
 			el=$(this).attr('id'); 
 			mode=$(this).attr('data-mode');
 			level=$(this).attr('data-level');
			hyper=window.T13NE.WriteWound(level,mode);
			$(this).html(hyper); ;
		});
	}); 	";
	}
   static public function WoundTable(){
  	return T13Types::tableDisplay(self::$wounds);	
  }
static public  function writeWound($level=0, $mode='jsvg',$lvl=0){
 	
 	switch ($mode){
 		case "text":
 		case "svg":
 			return "<div class=\"t13ne-wound\"><div><strong class=\"t13ne-woundname\">{$level['Name']}</strong><details><summary></summary><strong>{$level['Name']}</strong><p class=\"t13ne-base-pips\">Base Pips to summon: {$level['Base_Pips']}</p><p class=\"t13ne-min-pips\">Minimum Pips Required: {$level['Min_Pips']}</p><p class=\"t13ne-desc\">{$level['Description']}</p><details class=\"t13ne-roll\"><summary>Rules</summary>{$level['Wound_Roll']}</details><details class=\"t13ne-ordeal\"><summary>Ordeal Rules</summary>{$level['Wound_Ordeal']}</details><details class=\"t13ne-psych\"><summary>Psych Wounds</summary><details class=\"t13ne-negative\"><summary>Negative Psych</summary><p class=\"t13ne-normal\"><strong>Normal</strong>{$level['Negative_Normal']}</p><p class=\"t13ne-extreme\"><strong>Extreme</strong>{$level['Negative_Extreme']}</p></details><details class=\"t13ne-positive\"><summary>Positive Psych</summary><p class=\"t13ne-normal\"><strong>Normal</strong>{$level['Positive_Normal']}</p><p class=\"t13ne-extreme\"><strong>Extreme</strong>{$level['Positive_Extreme']}</p></details></details></details></div></div>";
 			break;
 		case "uni":
 		case "full":
 		case "fancy":
			return "<div class=\"t13ne-wound\"><div><details><summary><strong >Wound: </strong><span class=\"t13ne-woundname\">{$level['Name']}</span></summary><p class=\"t13ne-base-pips\">Base Pips to summon: {$level['Base_Pips']}</p><p class=\"t13ne-min-pips\">Minimum Pips Required: {$level['Min_Pips']}</p><p class=\"t13ne-desc\">{$level['Description']}</p><details class=\"t13ne-roll\"><summary>Rules: </summary>{$level['Wound_Roll']}</details><details class=\"t13ne-ordeal\"><summary>Ordeal Rules: </summary>{$level['Wound_Ordeal']}</details><details class=\"t13ne-psych\"><summary>Psych Wounds</summary><details class=\"t13ne-negative\"><summary>Negative Psych</summary><p class=\"t13ne-normal\"><strong>Normal: </strong>{$level['Negative_Normal']}</p><p class=\"t13ne-extreme\"><strong>Extreme: </strong>{$level['Negative_Extreme']}</p></details><details class=\"t13ne-positive\"><summary>Positive Psych</summary><p class=\"t13ne-normal\"><strong>Normal: </strong>{$level['Positive_Normal']}</p><p class=\"t13ne-extreme\"><strong>Extreme: </strong>{$level['Positive_Extreme']}</p></details></details></details></div></div>";
		break;
		case "jsvg":
		case "jscript":
			return '<div class="t13ne-wound"><div class="t13ne-woundrewrite" data-level='.$lvl.' data-mode="'.$mode.'"></div></div>';
			break;
		default:
			return "This ({$mode}) ain't recognised";
			//return  "<div class=\"t13ne-wound\"><div><details><summary><strong>Wound: </strong><span class=\"t13ne-woundname\">{$level['Name']}</span></summary><p class=\"t13ne-desc\">{$level['Description']}</p><details class=\"t13ne-roll\"><summary>Rules: </summary>{$level['Wound_Roll']}</details><details class=\"t13ne-ordeal\"><summary>Ordeal Rules: </summary>{$level['Wound_Ordeal']}</details><details class=\"t13ne-psych\"><summary>Psych Wounds</summary><details class=\"t13ne-negative\"><summary>Negative Psych</summary><p class=\"t13ne-normal\"><strong>Normal: </strong>{$level['Negative_Normal']}</p><p class=\"t13ne-extreme\"><strong>Extreme: </strong>{$level['Negative_Extreme']}</p></details><details class=\"t13ne-positive\"><summary>Positive Psych</summary><p class=\"t13ne-normal\"><strong>Normal: </strong>{$level['Positive_Normal']}</p><p class=\"t13ne-extreme\"><strong>Extreme: </strong>{$level['Positive_Extreme']}</p></details></details></details></div></div>";
			break;
 	}
 } 
 public static function getWound($level,$mode){
 	return self::writeWound(self::$wounds[$level],$mode,$level);
 }
}
?>